const previous = $('Build AI Prompt Compact').first().json;

let raw =
  $json.body?.response ||
  $json.response ||
  "";

raw = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

const start = raw.indexOf("{");
const end = raw.lastIndexOf("}");

if (start !== -1 && end !== -1) {
  raw = raw.slice(start, end + 1);
}

let ai_result;

try {
  ai_result = JSON.parse(raw);
} catch (e) {
  ai_result = {
    severity: "high",
    risk_score: 8,
    summary: "AI response parse failed.",
    affected_files: [],
    fix_suggestion: "Manual review required.",
    should_block_pipeline: true,
    raw_ai_response: raw,
    parse_error: e.message
  };
}

return [
  {
    json: {
      ...previous,
      ai_result
    }
  }
];

const data = $json.body || $json;

const trivy = data.trivy || {};
const semgrep = data.semgrep || {};
const zap = data.zap || {};

let findings = [];

// Trivy
for (const result of trivy.Results || []) {
  for (const vuln of result.Vulnerabilities || []) {
    findings.push({
      tool: "trivy",
      type: "container/dependency",
      severity: vuln.Severity || "UNKNOWN",
      cve: vuln.VulnerabilityID || "",
      package: vuln.PkgName || "",
      installed_version: vuln.InstalledVersion || "",
      fixed_version: vuln.FixedVersion || "",
      title: vuln.Title || "",
      file: result.Target || "",
      cvss:
        vuln.CVSS?.nvd?.V3Score ||
        vuln.CVSS?.redhat?.V3Score ||
        vuln.CVSS?.ghsa?.V3Score ||
        0,
      description: vuln.Description || ""
    });
  }
}

// Semgrep
for (const r of semgrep.results || []) {
  findings.push({
    tool: "semgrep",
    type: "sast",
    severity: r.extra?.severity || "UNKNOWN",
    rule_id: r.check_id || "",
    file: r.path || "",
    line: r.start?.line || null,
    message: r.extra?.message || "",
    code: r.extra?.lines || "",
    cvss: 0,
    description: r.extra?.metadata?.description || ""
  });
}

// ZAP
for (const site of zap.site || []) {
  for (const alert of site.alerts || []) {
    findings.push({
      tool: "zap",
      type: "dast",
      severity: alert.riskdesc || alert.risk || "UNKNOWN",
      url: alert.url || site["@name"] || "",
      alert: alert.alert || "",
      confidence: alert.confidence || "",
      description: alert.desc || "",
      solution: alert.solution || "",
      cvss: 0
    });
  }
}

return [
  {
    json: {
      total_findings: findings.length,
      findings
    }
  }
];

const findings = $json.findings || [];

function cleanHtml(text = "") {
  return String(text).replace(/<[^>]*>/g, "").trim();
}

function scoreFinding(f) {
  let score = 0;

  const tool = String(f.tool || "").toLowerCase();
  const severity = String(f.severity || "").toLowerCase();
  const title = String(f.title || f.alert || f.message || "").toLowerCase();

  if (tool === "semgrep") score += 40;
  if (tool === "trivy") score += 30;
  if (tool === "zap") score += 10;

  if (severity.includes("critical")) score += 50;
  else if (severity.includes("error")) score += 45;
  else if (severity.includes("high")) score += 40;
  else if (severity.includes("medium")) score += 25;
  else if (severity.includes("low")) score += 10;
  else if (severity.includes("informational")) score += 1;

  if (title.includes("sql injection")) score += 50;
  if (title.includes("xss")) score += 40;
  if (title.includes("command injection")) score += 50;
  if (title.includes("secret")) score += 35;

  if (f.file && f.line) score += 20;

  return score;
}

const enriched = findings.map(f => ({
  ...f,
  title: cleanHtml(f.title || f.alert || f.message || ""),
  description: cleanHtml(f.description || ""),
  solution: cleanHtml(f.solution || f.fix || ""),
  priority_score: scoreFinding(f)
}));

enriched.sort((a, b) => b.priority_score - a.priority_score);

const ai_findings = enriched.slice(0, 1);       // chỉ gửi 1 lỗi nặng nhất cho AI
const normal_findings = enriched.slice(1);      // lỗi còn lại để report

return [
  {
    json: {
      original_total_findings: findings.length,
      ai_findings,
      normal_findings,
      all_findings: enriched
    }
  }
];

const f = ($json.ai_findings || [])[0];

const ai_prompt = `
Return JSON only.

Analyze this high-priority vulnerability:
tool=${f.tool}
severity=${f.severity}
file=${f.file || ""}
line=${f.line || ""}
url=${f.url || ""}
title=${f.title || ""}
package=${f.package || ""}
cve=${f.cve || ""}
fixed_version=${f.fixed_version || ""}

JSON format:
{
 "severity":"",
 "risk_score":0,
 "summary":"",
 "affected_files":[],
 "fix_suggestion":"",
 "should_block_pipeline":false
}
`;

return [
  {
    json: {
      ...$json,
      ai_prompt
    }
  }
];

const findings = $json.findings || [];

let counts = {
  critical: 0,
  high: 0,
  medium: 0,
  low: 0,
  info: 0
};

for (const f of findings) {
  const sev = String(f.severity || "").toLowerCase();

  if (sev.includes("critical")) counts.critical++;
  else if (sev.includes("high")) counts.high++;
  else if (sev.includes("medium")) counts.medium++;
  else if (sev.includes("low")) counts.low++;
  else counts.info++;
}

let baseScore =
  counts.critical * 10 +
  counts.high * 7 +
  counts.medium * 4 +
  counts.low * 2;

let normalizedScore = Math.min(10, Math.round(baseScore / 5));

return [
  {
    json: {
      ...$json,
      severity_counts: counts,
      pre_risk_score: normalizedScore,
      should_block_precheck:
        counts.critical > 0 || counts.high >= 3 || normalizedScore >= 8
    }
  }
];

const findings = $json.findings || [];
const counts = $json.severity_counts || {};

let decision = "ALLOW";

if (
  $json.should_block_precheck === true ||
  (counts.critical || 0) > 0 ||
  (counts.high || 0) >= 1
) {
  decision = "BLOCK";
}

return [
  {
    json: {
      project_name: "dvwa-devsecops",
      total_findings: $json.total_findings || findings.length,
      risk_score: $json.pre_risk_score || 0,
      severity:
        (counts.critical || 0) > 0 ? "critical" :
        (counts.high || 0) > 0 ? "high" :
        (counts.medium || 0) > 0 ? "medium" :
        "low",

      ai_summary: "",
      ai_fix_suggestion: "",
      should_block_pipeline: decision === "BLOCK",
      pipeline_decision: decision,

      severity_counts: counts,

      ai_findings: [],
      normal_findings: findings,
      all_findings: findings
    }
  }
];

const ai = $json.ai_result || {};
const aiFindings = $json.ai_findings || [];
const normalFindings = $json.normal_findings || [];

return [
  {
    json: {
      report_type: "DevSecOps Security Report",
      total_findings: $json.original_total_findings,
      pipeline_decision: ai.should_block_pipeline ? "BLOCK" : "ALLOW",

      ai_analyzed_findings: aiFindings.map(f => ({
        severity: f.severity,
        tool: f.tool,
        title: f.title,
        file: f.file || f.url || "",
        line: f.line || "-",
        ai_summary: ai.summary,
        ai_fix_suggestion: ai.fix_suggestion,
        risk_score: ai.risk_score
      })),

      normal_findings_report: normalFindings.map(f => ({
        severity: f.severity,
        tool: f.tool,
        type: f.type,
        title: f.title,
        file_or_url: f.file || f.url || "",
        line: f.line || "-",
        suggested_fix: f.solution || f.fixed_version || ""
      }))
    }
  }
];

let raw = $json.response || "";
raw = raw.replace(/```json/g, "").replace(/```/g, "").trim();

let ai_result;

try {
  ai_result = JSON.parse(raw);
} catch (e) {
  ai_result = {
    severity: "medium",
    risk_score: 5,
    summary: "AI response parse failed.",
    affected_files: [],
    fix_suggestion: "Review manually.",
    should_block_pipeline: false
  };
}

return [
  {
    json: {
      ai_result,
      ai_findings: $json.ai_findings || [],
      normal_findings: $json.normal_findings || [],
      all_findings: $json.all_findings || [],
      original_total_findings: $json.original_total_findings || 0
    }
  }
];
